        try:
            response = requests.get(OTHER_SERVER_URL, timeout=10)
            print(f"✅ تم إرسال طلب إلى الحارس: {response.status_code}")
        except Exception as e:
            print(f"❌ فشل الاتصال بالخادم الآخر: {e}")
        time.sleep(300)

