# ============================================================
# 📦 الصور المشفرة (سيتم تعبئتها بعد التعديل)
# ============================================================
BASE64_IMAGES = {
    "M1": """""",
    "M2": """""",
    "M3": """""",
    "M4": """""",
    "M5": """""",
    "M6": """""",
    "M7": """""",
}

# ============================================================
# 📊 دالة التحقق من التعديل
# ============================================================
def check_modified():
    """التحقق من وجود الصور في الكود"""
    for key, value in BASE64_IMAGES.items():
        if not value or len(value) < 10:
            return False
    return True

# ============================================================
# 🔄 دالة تعديل الكود بنفسه
# ============================================================
def modify_script():
    """تعديل السكريبت ليحتوي على الصور مباشرة"""
    print("📸 جاري تحويل الصور وتعديل السكريبت...")
    
    # تحويل الصور إلى Base64
    base64_images = {}
    for i in range(1, 8):
        img_path = PICTURES_PATH + "M" + str(i) + ".jpg"
        key = "M" + str(i)
        
        if os.path.exists(img_path):
            with open(img_path, "rb") as f:
                base64_images[key] = base64.b64encode(f.read()).decode('utf-8')
            print("✅ " + key + ".jpg → " + str(len(base64_images[key])) + " حرف")
        else:
            print("❌ " + key + ".jpg غير موجود! استخدم صورة تجريبية")
            base64_images[key] = "R0lGODlhAQABAIAAAAAAAP///yH5BAEAAAAALAAAAAABAAEAAAIBRAA7"
    
    # إنشاء قاموس الصور كسلسلة
    images_str = "{\n"
    for key, value in base64_images.items():
        images_str += '    "' + key + '": """' + value + '""",\n'
    images_str += "}"
    
    # قراءة الملف الحالي
    with open(SCRIPT_PATH, 'r') as f:
        content = f.read()
    
    # استبدال قاموس الصور
    pattern = r'BASE64_IMAGES = \{[^}]*\}'
    replacement = 'BASE64_IMAGES = ' + images_str
    content = re.sub(pattern, replacement, content, flags=re.DOTALL)
    
    # حفظ الملف بعد التعديل
    with open(SCRIPT_PATH, 'w') as f:
        f.write(content)
    
    print("✅ تم تعديل السكريبت بنجاح! أصبح مستقلاً.")
    return True

# ============================================================
# 🔑 دوال التشغيل
# ============================================================
def auto_login():
    from instagrapi import Client
    cl = Client()
    if os.path.exists(SESSION_FILE):
        try:
            cl.load_settings(SESSION_FILE)
            print("✅ تم تحميل الجلسة المحفوظة!")
            return cl
        except:
            print("⚠️ فشل تحميل الجلسة، جاري تسجيل دخول جديد...")
    try:
        cl.login(USERNAME, PASSWORD)
        cl.dump_settings(SESSION_FILE)
        print("✅ تم تسجيل الدخول وحفظ الجلسة!")
        return cl
    except Exception as e:
        print("❌ فشل تسجيل الدخول: " + str(e))
        return None

def publish_photo(client, image_key):
    try:
        print("\n📸 نشر الصورة " + image_key + "...")
        
        encoded = BASE64_IMAGES.get(image_key)
        if not encoded:
            print("❌ لا توجد صورة للمفتاح " + image_key)
            return False
        
        caption = CAPTIONS.get(image_key, "⚠️ لا يوجد نص")
        
        image_data = base64.b64decode(encoded)
        temp_path = os.path.join(TEMP_DIR, image_key + ".jpg")
        
        with open(temp_path, "wb") as f:
            f.write(image_data)
        
        print("✅ تم فك تشفير الصورة (" + str(len(image_data)) + " بايت)")
        result = client.photo_upload(temp_path, caption)
        print("✅ تم النشر! 🔗 https://www.instagram.com/p/" + result.code + "/")
        
        try:
            os.remove(temp_path)
        except:
            pass
        return True
    except Exception as e:
        print("❌ فشل النشر: " + str(e))
        return False

def get_current_image(offset=0):
    schedule = ["M1", "M2", "M3", "M4", "M5", "M6", "M7"]
    index = (offset % 7)
    return schedule[index]

# ============================================================
# 🚀 التشغيل الرئيسي
# ============================================================
def main():
    print("="*60)
    print("📸 Instagram Auto Poster - النسخة النهائية")
    print("="*60)
    
    # التحقق من التعديل
    modified = check_modified()
    
    # إذا لم يتم التعديل بعد، نقوم بالتعديل
    if not modified:
        print("\n🔄 هذه هي المرة الأولى للتشغيل.")
        print("📸 سيتم تحويل الصور وتعديل السكريبت...")
        modify_script()
        print("\n✅ تم التعديل! أعد تشغيل السكريبت الآن.")
        print("🔄 قم بتشغيل: python " + os.path.basename(SCRIPT_PATH))
        return
    
    # تشغيل خادم الويب
    print("\n🌐 جاري تشغيل خادم Keep-Alive...")
    threading.Thread(target=run_web_server, daemon=True).start()
    print("✅ خادم Keep-Alive يعمل على المنفذ 8080")
    
    # بدء مهمة إرسال الطلبات إلى الخادم الآخر
    if OTHER_SERVER_URL and OTHER_SERVER_URL != "https://server-b.onrender.com/keepalive":
        print("🔄 جاري تشغيل مهمة إرسال الطلبات إلى الخادم الآخر...")
        threading.Thread(target=send_keepalive, daemon=True).start()
        print("✅ سيتم إرسال طلبات إلى الخادم الآخر كل 5 دقائق")
    
    # تسجيل الدخول
    print("\n🔑 جاري تسجيل الدخول إلى إنستغرام...")
    client = auto_login()
    if not client:
        print("❌ فشل تسجيل الدخول! تحقق من اسم المستخدم وكلمة المرور.")
        return
    print("✅ تم تسجيل الدخول بنجاح!")
    
    # النشر
    print("\n📋 M1→Rasputin | M2→Saladin | M3→Effortless | M4→MLK | M5→Gandhi | M6→Compassion | M7→Smarter")
    print("🛑 للإيقاف: Ctrl+C")
    print("="*60 + "\n")
    
    image_index = 0
    
    while True:
        try:
            image_key = get_current_image(image_index)
            print("\n" + "="*60)
            print("📅 " + datetime.now().strftime('%Y-%m-%d %H:%M:%S'))
            print("📸 نشر الصورة: " + image_key)
            print("="*60)
            
            if publish_photo(client, image_key):
                print("✅ تم نشر " + image_key + " بنجاح!")
            else:
                print("❌ فشل نشر " + image_key)
            
            image_index += 1
            
            print("\n⏳ انتظار " + str(INTERVAL_HOURS) + " ساعات للنشر التالي...")
            time.sleep(INTERVAL_HOURS * 3600)
            
        except KeyboardInterrupt:
            print("\n🛑 تم إيقاف البوت بواسطة المستخدم.")
            break
        except Exception as e:
            print("❌ خطأ غير متوقع: " + str(e))
            print("⏳ إعادة المحاولة بعد 5 دقائق...")
            time.sleep(300)

if __name__ == "__main__":
    main()
